class HeatingPlan {
    private final TempRange permittedRange;

    HeatingPlan(TempRange permittedRange) {
        this.permittedRange = permittedRange;
    }

    boolean isWithinPermittedRange(TempRange actualRange) {
        return permittedRange.contains(actualRange);
    }
}

void checkTemperatureRange(Room room, HeatingPlan plan) {
    TempRange dailyRange = room.getDaysTempRange();
    if (!plan.isWithinPermittedRange(dailyRange)) {
        alerts.add("Room temperature outside heating plan range");
    }
}
